const { pregunta, lead_tipo, whatsapp } = $input.first().json;

// Mapeo de lead_tipo a categorías para filtrar
const categoriasMap = {
  'KIDS': ['KIDS', 'GENERAL', 'METODOLOGIA'],
  'KIDS-ADOLESCENTES': ['KIDS', 'GENERAL', 'METODOLOGIA'],
  'ADULTO': ['ADULTOS', 'GENERAL', 'METODOLOGIA', 'PRECIOS', 'PARTICULARES'],
  'PERSONALIZADO': ['PARTICULARES', 'GENERAL', 'METODOLOGIA', 'PRECIOS'],
  'AU_PAIR': ['AU_PAIR', 'GENERAL', 'METODOLOGIA', 'PRECIOS']
};

const categorias = categoriasMap[lead_tipo] || ['GENERAL'];

return [{
  json: {
    pregunta: pregunta || '',
    lead_tipo: lead_tipo || 'GENERAL',
    whatsapp: whatsapp || '',
    categorias: categorias,
    timestamp: new Date().toISOString()
  }
}];

const results = $input.all();
const pregunta = $('Preparar Query').item.json.pregunta;
const lead_tipo = $('Preparar Query').item.json.lead_tipo;
const categorias = $('Preparar Query').item.json.categorias;

// Procesar resultados del RAG
let contenido = '';
let fuentes = [];

results.forEach(result => {
  if (result.json && result.json.pageContent) {
    contenido += result.json.pageContent + '\n\n';

    // Extraer metadata si existe
    if (result.json.metadata) {
      const meta = result.json.metadata;
      if (meta.titulo && !fuentes.includes(meta.titulo)) {
        fuentes.push(meta.titulo);
      }
    }
  }
});

// Si no hay resultados, responder con info genérica
if (!contenido.trim()) {
  contenido = `No encontré información específica sobre "${pregunta}" en la base de datos. Por favor, consultá directamente a Fla para más detalles.`;
}

return [{
  json: {
    exito: true,
    pregunta: pregunta,
    lead_tipo: lead_tipo,
    contenido: contenido.trim(),
    fuentes: fuentes.length > 0 ? fuentes.join(', ') : 'Base de datos general',
    cantidad_resultados: results.length
  }
}];
